package com.hospital.management.filter;
import javax.servlet.*;import javax.servlet.annotation.WebFilter;import javax.servlet.http.HttpServletResponse;import java.io.IOException;
@WebFilter("/*") public class SecurityHeadersFilter implements Filter {public void doFilter(ServletRequest q,ServletResponse s,FilterChain c)throws IOException,ServletException{HttpServletResponse r=(HttpServletResponse)s;r.setHeader("X-Content-Type-Options","nosniff");r.setHeader("X-Frame-Options","DENY");r.setHeader("Referrer-Policy","strict-origin-when-cross-origin");r.setHeader("Cache-Control","no-store, no-cache, must-revalidate");r.setHeader("Pragma","no-cache");r.setHeader("Content-Security-Policy","default-src 'self'; style-src 'self' https://cdn.jsdelivr.net; script-src 'self' https://cdn.jsdelivr.net; img-src 'self' data:; font-src 'self' https://cdn.jsdelivr.net; frame-ancestors 'none'; form-action 'self'");c.doFilter(q,s);}}
